import vastorbit._config.config as conf


def vast_logo_png():
    """
    Generates the png code
    for the VAST logo.

    Returns
    -------
    str
        VAST logo.

    Examples
    --------
    The following code demonstrates the
    usage of the function.

    .. ipython:: python

        # Import the function.
        from vastorbit._utils._logo import vast_logo_png

        # result
        vast_logo_png()

    .. note::

        These functions serve as utilities to
        construct others, simplifying the overall
        code.
    """
    return "data:image/png;base64,"


def vastorbit_logo_html(size: str = "50%") -> str:
    """
    Generates the HTML code
    for the vastorbit logo.

    Parameters
    ----------
    size: str, optional
        Size for the logo. It should be
        a percentage like '50%' or '99%'.

    Returns
    -------
    str
        vastorbit logo.

    Examples
    --------
    The following code demonstrates the
    usage of the function.

    .. ipython:: python

        # Import the function.
        from vastorbit._utils._logo import vastorbit_logo_html

        # result
        logo = vastorbit_logo_html()

    .. ipython:: python
        :suppress:

        html_file = open("SPHINX_DIRECTORY/figures/utils_vastorbit_logo.html", "w")
        html_file.write(logo)
        html_file.close()

    .. raw:: html
        :file: SPHINX_DIRECTORY/figures/utils_vastorbit_logo.html

    .. note::

        These functions serve as utilities to
        construct others, simplifying the overall
        code.
    """

    # SVG content of VAST Data logo

    theme = conf.get_option("theme")

    bg = "E8EFF7"
    if theme == "light":
        bg = "000000"

    svg_content = (
        """<?xml version="1.0" encoding="UTF-8"?>
        <svg class="vob-logo-mark" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 150 150">
          <defs>
            <style>
              .vob-logo-mark .cls-1 {
                fill: var(--color-foreground-primary, #"""
        + bg
        + """);
              }

              .vob-logo-mark .cls-2 {
                fill: #29b8ff;
              }

              .vob-logo-mark .cls-3 {
                fill: none;
              }
            </style>
          </defs>
          <path class="cls-3" d="M0,0H150V150H0V0Z"/>
          <path class="cls-1" d="M6.05,28.07c-.14-4,2.9-7.93,6.85-8.65,11.23-.05,22.46,0,33.69-.02,2.78-.1,5.32,2.33,5.44,5.09,.09,2.23,.06,4.47,.02,6.7,.02,2.65-2.3,5.21-5.02,5.1-5.85,.06-11.7-.11-17.56,.08,.83,1.87,16.93,28.39,23.89,39.92,1.06,1.51,1.46,3.44,.96,5.23-.66,2.16-8.13,7.02-10.4,6.76-1.95,.06-3.5-1.4-4.41-3-10.44-17.09-20.75-34.25-31.25-51.3-1.14-1.78-2.24-3.73-2.23-5.91"/>
          <path class="cls-1" d="M98.55,73.39c1.09-1.81,2.13-4.07,4.39-4.59,2.4-.71,10.38,4.07,11.2,6.14,.64,2.26,.09,4.71-1.14,6.68-9.95,16.53-19.86,33.09-29.81,49.62-1.32,2.13-2.42,4.66-4.78,5.85-3.45,1.86-7.99,.14-10.04-3.02-5.51-9.28-11.01-18.57-16.54-27.84-.88-1.37-.93-3.15-.46-4.66,.67-1.63,2.29-2.51,3.76-3.31,1.64-.88,3.21-1.9,4.92-2.65,2.17-.96,4.88,.04,6.1,2.05,3,4.85,5.76,9.85,8.86,14.65,.67-.94,16.34-26.9,23.55-38.91"/>
          <path class="cls-2" d="M65.9,24.16c.59-3.07,4.02-4.48,6.86-4.38,21.14-.03,42.28-.04,63.42-.04,5.72-.14,9.69,7.14,6.83,11.97-5.36,8.87-10.73,17.72-16.03,26.62-.81,1.53-1.99,3.01-3.78,3.36-1.7,.63-3.4-.36-4.84-1.19-1.58-.95-3.22-1.79-4.78-2.77-2.01-1.29-2.97-4.13-1.85-6.3,2.79-5.14,6.18-9.94,8.9-15.11-16.7-.05-33.41,0-50.11-.04-2.64,.05-4.89-2.49-4.74-5.09,.04-2.35-.15-4.71,.11-7.05"/>
        </svg>
    """
    )

    # Inline the SVG directly (NOT a base64 <img>): an <img>-embedded SVG is an
    # isolated document that cannot read the page's CSS variables, so the Furo
    # light/dark theming below would never apply. Inlined, it does.
    svg_inline = svg_content.replace('<?xml version="1.0" encoding="UTF-8"?>\n', "")
    svg_inline = svg_inline.replace(
        'class="vob-logo-mark"',
        f'class="vob-logo-mark" style="width:{size};height:auto;"',
    )
    return f"<center>{svg_inline}</center>"


def vastorbit_logo_str() -> str:
    """
    Generates the Python ``string``
    that represents the vastorbit logo.

    Returns
    -------
    str
        vastorbit logo.

    Examples
    --------
    The following code demonstrates the
    usage of the function.

    .. ipython:: python

        # Import the function.
        from vastorbit._utils._logo import vastorbit_logo_str

        # result
        logo = vastorbit_logo_str()

        # printing the result
        print(logo)

    .. note::

        These functions serve as utilities to
        construct others, simplifying the overall
        code.
    """
    img = "    __________  _____________   \n"
    img += "    \\        | |            /   \n"
    img += "     \\   ____| |________   /    \n"
    img += "      \\   \\           /   /    \n"
    img += "       \\   \\         /___/     \n"
    img += "        \\___\\       ____       \n"
    img += "          _____    /   /         \n"
    img += "          \\    \\  /   /        \n"
    img += "           \\    \\/   /         \n"
    img += "            \\       /           \n"
    img += "             \\     /            \n"
    img += "              \\___/             \n"
    img += "\n"
    return img
